import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Grid,
  TextField,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  Card,
  CardContent,
  IconButton,
  Tooltip,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  LinearProgress,
  Alert,
  LinearProgress as MuiLinearProgress,
} from '@mui/material';
import {
  Search,
  Download,
  Print,
  Inventory,
  Refresh,
  Warning,
  CheckCircle,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { reportService } from '../../services/reportService';
import { itemService } from '../../services/itemService';

const StockReport = () => {
  const [filters, setFilters] = useState({
    startDate: new Date(new Date().setDate(1)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
    itemId: '',
    brandId: '',
    groupId: '',
  });
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [summary, setSummary] = useState(null);
  const [items, setItems] = useState([]);
  const [brands, setBrands] = useState([]);
  const [groups, setGroups] = useState([]);

  useEffect(() => {
    fetchMasterData();
  }, []);

  const fetchMasterData = async () => {
    try {
      const [itemsData, brandsData, groupsData] = await Promise.all([
        itemService.getAll(0, 1000),
        // Add brandService and groupService calls
      ]);
      setItems(itemsData.content || []);
    } catch (error) {
      console.error('Failed to fetch master data:', error);
    }
  };

  const fetchReport = async () => {
    if (!filters.startDate || !filters.endDate) {
      setError('Please select both start and end dates');
      return;
    }

    setLoading(true);
    setError('');
    try {
      const response = await reportService.getStockReport(filters);
      setData(response.content || []);
      setSummary(response.summary || null);
      toast.success('Stock report loaded successfully');
    } catch (error) {
      setError('Failed to load stock report');
      toast.error('Failed to load stock report');
    } finally {
      setLoading(false);
    }
  };

  const getStockStatus = (item) => {
    const currentStock = item.currentStock || 0;
    const minStock = item.minStockLevel || 0;
    const maxStock = item.maxStockLevel || 0;

    if (currentStock <= 0) {
      return { label: 'Out of Stock', color: 'error' };
    }
    if (currentStock <= minStock) {
      return { label: 'Critical Stock', color: 'error' };
    }
    if (currentStock <= minStock * 2) {
      return { label: 'Low Stock', color: 'warning' };
    }
    if (currentStock >= maxStock) {
      return { label: 'Over Stock', color: 'info' };
    }
    return { label: 'In Stock', color: 'success' };
  };

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <Inventory sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Stock Report
          </Typography>
          <Typography variant="body2" color="textSecondary">
            View and analyze inventory stock
          </Typography>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      <Paper sx={{ p: 3, borderRadius: 2, mb: 3 }}>
        <Grid container spacing={2} alignItems="center">
          <Grid item xs={12} md={3}>
            <TextField
              fullWidth
              label="Start Date"
              type="date"
              name="startDate"
              value={filters.startDate}
              onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
              InputLabelProps={{ shrink: true }}
            />
          </Grid>
          <Grid item xs={12} md={3}>
            <TextField
              fullWidth
              label="End Date"
              type="date"
              name="endDate"
              value={filters.endDate}
              onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
              InputLabelProps={{ shrink: true }}
            />
          </Grid>
          <Grid item xs={12} md={3}>
            <Button
              fullWidth
              variant="contained"
              startIcon={<Search />}
              onClick={fetchReport}
              disabled={loading}
              sx={{ height: 56 }}
            >
              {loading ? 'Loading...' : 'Generate'}
            </Button>
          </Grid>
          <Grid item xs={12} md={3}>
            <Box display="flex" gap={1}>
              <Button variant="outlined" startIcon={<Refresh />} onClick={fetchReport}>
                Refresh
              </Button>
              <Button variant="outlined" startIcon={<Download />}>
                Export
              </Button>
              <Button variant="outlined" startIcon={<Print />}>
                Print
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>

      {summary && (
        <Grid container spacing={3} mb={3}>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Total Items
                </Typography>
                <Typography variant="h5">{summary.totalItems}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Total Stock Value
                </Typography>
                <Typography variant="h5" color="primary">
                  ₹{summary.totalStockValue?.toFixed(2)}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Low Stock Items
                </Typography>
                <Typography variant="h5" color="warning">
                  {summary.lowStockItems || 0}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card>
              <CardContent>
                <Typography variant="body2" color="textSecondary">
                  Out of Stock
                </Typography>
                <Typography variant="h5" color="error">
                  {summary.outOfStock || 0}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        </Grid>
      )}

      {loading ? (
        <Box sx={{ width: '100%', py: 4 }}>
          <MuiLinearProgress />
          <Typography textAlign="center" sx={{ mt: 2 }} color="textSecondary">
            Loading stock data...
          </Typography>
        </Box>
      ) : data.length > 0 ? (
        <Paper sx={{ p: 2, borderRadius: 2 }}>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                  <TableCell>Code</TableCell>
                  <TableCell>Item Name</TableCell>
                  <TableCell>Brand</TableCell>
                  <TableCell>Group</TableCell>
                  <TableCell align="right">Opening Stock</TableCell>
                  <TableCell align="right">Purchases</TableCell>
                  <TableCell align="right">Sales</TableCell>
                  <TableCell align="right">Closing Stock</TableCell>
                  <TableCell>Status</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((item, index) => {
                  const stockStatus = getStockStatus(item);
                  return (
                    <TableRow key={index} hover>
                      <TableCell>
                        <Typography variant="body2" fontWeight={500}>
                          {item.itemCode}
                        </Typography>
                      </TableCell>
                      <TableCell>{item.itemName}</TableCell>
                      <TableCell>{item.brandName || '-'}</TableCell>
                      <TableCell>{item.groupName || '-'}</TableCell>
                      <TableCell align="right">
                        {item.openingStock || 0}
                      </TableCell>
                      <TableCell align="right">
                        {item.totalPurchases || 0}
                      </TableCell>
                      <TableCell align="right">
                        {item.totalSales || 0}
                      </TableCell>
                      <TableCell align="right">
                        <Typography fontWeight="bold" color="primary">
                          {item.closingStock || 0}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        <Chip
                          label={stockStatus.label}
                          color={stockStatus.color}
                          size="small"
                          icon={stockStatus.color === 'success' ? <CheckCircle /> : <Warning />}
                        />
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </TableContainer>
        </Paper>
      ) : (
        <Paper sx={{ p: 4, textAlign: 'center', borderRadius: 2 }}>
          <Typography color="textSecondary">
            {filters.startDate && filters.endDate
              ? 'No stock data found for the selected period'
              : 'Select date range and generate report'}
          </Typography>
        </Paper>
      )}
    </Box>
  );
};

export default StockReport;
